-- 192.168.201.0/24 IP 대장 초기 시드.
--
-- 오픈스택 대상(VM / Floating IP / router 외부 GW)은 각 팜 neutron 라이브 실측으로
-- 생성했다(2026-07-24, sre-srv-0058=팜A / 0047=팜C / 0048=팜D). 개인 단말·물리 서버·
-- wg3 DNAT VIP 는 neutron 에 없으므로 운영자 정리본을 그대로 유지했다.
--
-- 1회 로드용. ON CONFLICT DO NOTHING 이라 이미 있는 IP 행은 건드리지 않는다(운영자 수정
-- 보존). 마이그레이션(010)과 분리돼 sync/migrate 재실행에 자동 재적용되지 않는다.
--
-- 로드(RW 권한 필요): Vault 동적 RW 자격으로 psql 접속 후 실행.
--   eval "$(vault read -format=json database/creds/<rw-role> | \
--     jq -r '"export PGUSER=\(.data.username) PGPASSWORD=\(.data.password)"')"
--   psql "host=<db-host> port=5432 dbname=vctl sslmode=verify-full sslrootcert=<sre-root-ca.pem>" \
--     -f seed/ip_allocations_seed.sql
--
-- farm VIP: A=192.168.201.150 / B=192.168.201.245(Infra HA, 201 미사용) / C=192.168.201.130 / D=192.168.201.90

ON CONFLICT (ip) DO NOTHING;
